// Base prices for deterministic computation
const BASE = {
 WHEAT:2275,RICE:2800,BASMATI_RICE:4800,MAIZE:1900,BAJRA:2200,JOWAR:2800,RAGI:3500,
 SOYBEAN:4200,MUSTARD:5100,GROUNDNUT:5200,SUNFLOWER:5800,SESAME:9000,
 COTTON:6700,SUGARCANE:340,JUTE:5000,
 ARHAR:6800,MOONG:7200,URAD:6500,CHANA:5200,MASOOR:6200,
 ONION:850,TOMATO:1200,POTATO:1050,GARLIC:3000,CHILLI:9500,
 CABBAGE:600,CAULIFLOWER:800,BRINJAL:700,BHINDI:900,
 TURMERIC:7500,GINGER:5000,CORIANDER:4500,
 BANANA:1500,APPLE:8000,MANGO:4000,GRAPES:5000,POMEGRANATE:7000,
}
const SPREAD = {
 WHEAT:150,RICE:180,BASMATI_RICE:400,MAIZE:140,BAJRA:180,JOWAR:200,RAGI:300,
 SOYBEAN:280,MUSTARD:280,GROUNDNUT:400,SUNFLOWER:300,SESAME:500,
 COTTON:500,SUGARCANE:20,JUTE:300,
 ARHAR:400,MOONG:500,URAD:450,CHANA:350,MASOOR:400,
 ONION:400,TOMATO:600,POTATO:250,GARLIC:1200,CHILLI:2000,
 CABBAGE:200,CAULIFLOWER:250,BRINJAL:200,BHINDI:300,
 TURMERIC:1000,GINGER:1500,CORIANDER:1000,
 BANANA:400,APPLE:1500,MANGO:1000,GRAPES:1000,POMEGRANATE:1500,
}

export function getPrice(cropId, mandiId) {
 const base = BASE[cropId] || 2000
 const spread = SPREAD[cropId] || 200
 const seed = [...(cropId + mandiId)].reduce((a, c) => a + c.charCodeAt(0), 0)
 const r1 = ((seed * 9301 + 49297) % 233280) / 233280
 const r2 = ((seed * 1234 + 7777) % 99991) / 99991
 const modal = Math.round(base + (r1 - 0.5) * spread * 0.4)
 const min   = Math.round(modal - spread * 0.3 - r2 * spread * 0.15)
 const max   = Math.round(modal + spread * 0.3 + r2 * spread * 0.15)
 const changePct = parseFloat(((r1 - 0.5) * 8).toFixed(1))
 const trend = changePct > 0.5 ? 'up' : changePct < -0.5 ? 'down' : 'flat'
 const msp = CROP_INFO[cropId]?.msp || null
 const confidence = parseFloat((0.65 + r2 * 0.30).toFixed(2))
 return {cropId,cropName:CROP_INFO[cropId]?.name||cropId,modal,min,max,changePct,trend,msp,confidence,unit:'Quintal'}
}

export function getStates()                    { return [...new Set(MANDI_DB.map(m=>m.state))].sort() }
export function getDistricts(state)            { return [...new Set(MANDI_DB.filter(m=>m.state===state).map(m=>m.district))].sort() }
export function getSubDistricts(state,district){ return [...new Set(MANDI_DB.filter(m=>m.state===state&&m.district===district).map(m=>m.sub))].sort() }
export function getMandis(state,district,sub)  { return MANDI_DB.filter(m=>(!state||m.state===state)&&(!district||m.district===district)&&(!sub||m.sub===sub)) }
export function getCrops(state)                { const ids=(STATE_CROPS[state]||Object.keys(CROP_INFO)); return ids.filter(id=>CROP_INFO[id]).map(id=>({id,name:CROP_INFO[id].name,cat:CROP_INFO[id].cat})) }
